export function rateLimiter<T extends (...args: any[]) => any>(
  fn: T,
  limit: number,
  windowMs: number
): (...args: Parameters<T>) => boolean {
  const calls: number[] = [];

  return (...args: Parameters<T>): boolean => {
    const now = Date.now();
    // Remove old calls outside window
    while (calls.length > 0 && now - calls[0] > windowMs) {
      calls.shift();
    }

    if (calls.length < limit) {
      calls.push(now);
      fn(...args);
      return true;
    }
    return false;  // Rate limited
  };
}
